def gen(rng, size):
    n = max(1, size)
    ops = ['+', '-', '*']
    tokens = [str(rng.randrange(-50, 51))]
    stack_count = 1
    while len(tokens) < n:
        if stack_count >= 2 and rng.random() < 0.5:
            tokens.append(ops[rng.randrange(len(ops))])
            stack_count -= 1
        else:
            tokens.append(str(rng.randrange(-20, 21)))
            stack_count += 1
    while stack_count > 1:
        tokens.append(ops[rng.randrange(len(ops))])
        stack_count -= 1
    return [tokens]

