class Solution:
    def evalRPN(self, tokens):
        def apply(a, b, op):
            if op == '+':
                return a + b
            if op == '-':
                return a - b
            if op == '*':
                return a * b
            q = abs(a) // abs(b)
            if (a < 0) != (b < 0):
                q = -q
            return q
        stack = []
        for t in tokens:
            if t in ('+', '-', '*', '/'):
                b = stack.pop()
                a = stack.pop()
                stack.append(apply(a, b, t))
            else:
                stack.append(int(t))
        return stack[0]

